static const char* get_config(const char *env_var, const char *fallback) {
    const char *val = getenv(env_var);
    if (val != NULL && strlen(val) > 0) {
        return val;
    }
    fprintf(stderr, "WARNING: Environment variable %s not set, using fallback. "
                    "Set environment variables for proper security.\n", env_var);
    return fallback;
}

